/* Minified main.js (updated for robustness) */let AppState = { currentUser: null, currentSection: "dashboard", init() { const user = StorageManager.getCurrentUser(); if (!user) { this.showLoginPage() } else { this.showDashboard() } }, showLoginPage() { document.body.style.display = 'block'; const indexPage = document.querySelector('.login-page'); if (indexPage) { indexPage.style.display = 'flex' } }, showDashboard() { const user = StorageManager.getCurrentUser(); if (!user) return; this.currentUser = user; this.updateDashboard(user.id) }, updateDashboard(userId) { this.updateUserGreeting(userId); this.updateProgressBar(userId); this.updateStats(userId); GameificationEngine.checkAllBadges(userId); GamificationRenderer.updateDashboardGamification(userId) }, updateUserGreeting(userId) { const user = StorageManager.getUser(userId); const el = document.getElementById('userGreeting'); if (el && user) el.textContent = `Welcome back, ${user.studentName}!` }, updateProgressBar(userId) { const progress = StorageManager.getProgress(userId); const percent = StorageManager.getOverallProgress(userId); const el1 = document.getElementById('overallProgress'); if (el1) el1.textContent = percent + '%'; const pb = document.getElementById('courseProgressBar'); if (pb) pb.style.width = percent + '%'; const el2 = document.getElementById('progressText'); if (el2) el2.textContent = `${progress.lessonsCompleted.length} of 5 days completed` }, updateStats(userId) { const gamification = StorageManager.getGamification(userId); const el1 = document.getElementById('totalPoints'); if (el1) el1.textContent = gamification.totalPoints; const el2 = document.getElementById('badgeCount'); if (el2) el2.textContent = StorageManager.getBadges(userId).length; const levelInfo = GameificationEngine.getLevelInfo(gamification.totalPoints); const el3 = document.getElementById('currentLevel'); if (el3) el3.textContent = levelInfo.name; this.updateDailyChallenge(userId) }, updateDailyChallenge(userId) { const challenge = StorageManager.getDailyChallenge(userId); const titleEl = document.getElementById('dailyChallenge'); const statusEl = document.getElementById('challengeStatus'); if (!challenge || !challenge.challenge) return; if (titleEl) titleEl.innerHTML = `<strong>${challenge.challenge.title}</strong><br><small>${challenge.challenge.description}</small>`; if (statusEl) { if (challenge.completed) { statusEl.innerHTML = '<span class="badge bg-success">Completed Today!</span>' } else { statusEl.innerHTML = '<span class="badge bg-warning">Not Completed</span>' } } } }; document.addEventListener('DOMContentLoaded', () => { StorageManager.init(); const user = StorageManager.getCurrentUser(); if (user) { setupDashboard(user.id) } else { setupLoginForm() } if ('serviceWorker' in navigator) { navigator.serviceWorker.register('service-worker.js').then(() => { console.log('Service worker registered') }).catch(() => { }) } }); function setupLoginForm() { const loginForm = document.getElementById('loginForm'); const demoBtn = document.getElementById('demoBtn'); if (loginForm) { loginForm.addEventListener('submit', e => { e.preventDefault(); const studentName = document.getElementById('studentName').value.trim(); const studentID = document.getElementById('studentID').value.trim(); const gradeLevel = document.getElementById('gradeLevel').value; if (!studentName || !studentID || !gradeLevel) { alert('Please fill in all fields'); return } const result = StorageManager.registerUser({ studentName, studentID, gradeLevel }); if (result.success) { StorageManager.setCurrentUser(result.user.id); window.location.href = 'dashboard.html' } else { const existingUser = StorageManager.getUser(studentID); if (existingUser) { StorageManager.setCurrentUser(existingUser.id); window.location.href = 'dashboard.html' } } }) } if (demoBtn) { demoBtn.addEventListener('click', () => { const result = StorageManager.registerUser({ studentName: 'Demo Student', studentID: 'DEMO001', gradeLevel: 'Grade 10' }); if (result.success) { StorageManager.setCurrentUser(result.user.id); window.location.href = 'dashboard.html' } }) } } function setupDashboard(userId) { const user = StorageManager.getUser(userId); if (!user) return; AppState.currentUser = user; AppState.updateDashboard(userId); setupNavigation(userId); const logoutBtn = document.getElementById('logoutBtn'); if (logoutBtn) { logoutBtn.addEventListener('click', e => { e.preventDefault(); StorageManager.logout(); window.location.href = 'index.html' }) } setupQuickLinks(userId); setupDailyChallenge(userId); renderSection('dashboard', userId) } function setupNavigation(userId) { document.querySelectorAll('.nav-link').forEach(link => { link.addEventListener('click', e => { const section = e.currentTarget.dataset.section; if (section) { e.preventDefault(); document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active')); e.currentTarget.classList.add('active'); renderSection(section, userId) } }) }) } function renderSection(section, userId) { AppState.currentSection = section; document.querySelectorAll('.content-section').forEach(s => s.style.display = 'none'); const titles = { dashboard: 'Dashboard', lessons: 'Lessons', quiz: 'Quizzes', assignments: 'Assignments', forum: 'Discussion Forum', gamification: 'Achievements', profile: 'My Profile' }; const titleEl = document.getElementById('pageTitle'); if (titleEl) titleEl.textContent = titles[section] || 'Dashboard'; const sectionEl = document.getElementById(section + '-section'); if (sectionEl) sectionEl.style.display = 'block'; switch (section) { case 'lessons': LessonRenderer.renderLessonList('lessonsList', userId); break; case 'quiz': QuizRenderer.renderQuizList('quizList', userId); break; case 'assignments': AssignmentRenderer.renderAssignmentList('assignmentsList', userId); break; case 'forum': ForumRenderer.renderForum('forumPosts', userId); ForumRenderer.setupForumForm(userId); break; case 'gamification': GamificationRenderer.renderBadges('badgesList', userId); GamificationRenderer.renderLevelInfo('levelInfo', userId); GamificationRenderer.renderLeaderboard('leaderboard'); break; case 'profile': renderProfile(userId); break }window.scrollTo(0, 0) } function renderProfile(userId) { const user = StorageManager.getUser(userId); const progress = StorageManager.getProgress(userId); const gamification = StorageManager.getGamification(userId); const levelInfo = GameificationEngine.getLevelInfo(gamification.totalPoints); let profileHtml = `<div class="row"><div class="col-md-4 text-center mb-4"><div style="width: 120px; height: 120px; background: linear-gradient(135deg, var(--primary-color), var(--secondary-color)); border-radius: 50%; margin: 0 auto; display: flex; align-items: center; justify-content: center; color: white; font-size: 48px;">${user.studentName.charAt(0).toUpperCase()}</div><h4 class="mt-3">${user.studentName}</h4><p class="text-muted">${user.studentID}</p></div><div class="col-md-8"><h6>Student Details</h6><table class="table table-sm"><tr><td><strong>Name:</strong></td><td>${user.studentName}</td></tr><tr><td><strong>Student ID:</strong></td><td>${user.studentID}</td></tr><tr><td><strong>Grade:</strong></td><td>${user.gradeLevel}</td></tr><tr><td><strong>Joined:</strong></td><td>${new Date(user.registeredDate).toLocaleDateString()}</td></tr><tr><td><strong>Last Access:</strong></td><td>${new Date(user.lastAccess).toLocaleDateString()}</td></tr></table></div></div><hr class="my-4"><div class="row"><div class="col-md-6"><h6>Learning Progress</h6><table class="table table-sm"><tr><td>Lessons Completed:</td><td><strong>${progress.lessonsCompleted.length}/5</strong></td></tr><tr><td>Quizzes Passed:</td><td><strong>${progress.quizzesTaken.length}/5</strong></td></tr><tr><td>Assignments Submitted:</td><td><strong>${progress.assignmentsSubmitted.length}/5</strong></td></tr><tr><td>Forum Posts:</td><td><strong>${progress.forumPostsCount}</strong></td></tr></table></div><div class="col-md-6"><h6>Achievements</h6><table class="table table-sm"><tr><td>Current Level:</td><td><strong>${levelInfo.name}</strong></td></tr><tr><td>Total Points:</td><td><strong>${gamification.totalPoints}</strong></td></tr><tr><td>Badges Earned:</td><td><strong>${StorageManager.getBadges(userId).length}</strong></td></tr><tr><td>Overall Progress:</td><td><strong>${StorageManager.getOverallProgress(userId)}%</strong></td></tr></table></div></div>`; const pi = document.getElementById('profileInfo'); if (pi) pi.innerHTML = profileHtml; let statsHtml = `<div class="progress mb-3"><div class="progress-bar bg-success" role="progressbar" style="width: ${StorageManager.getOverallProgress(userId)}%"></div></div><p class="small text-muted mb-3">Overall Course Completion: ${StorageManager.getOverallProgress(userId)}%</p><h6 class="mt-4">Top 3 Badges</h6><div class="d-flex gap-2 mb-3">`; const badges = StorageManager.getBadges(userId); badges.slice(0, 3).forEach(badge => { statsHtml += `<div class="badge badge-icon" title="${badge.description}">${badge.icon}</div>` }); statsHtml += '</div>'; if (badges.length === 0) { statsHtml += '<p class="text-muted small">Complete lessons and activities to earn badges!</p>' } const si = document.getElementById('statsInfo'); if (si) si.innerHTML = statsHtml } function setupQuickLinks(userId) { document.querySelectorAll('.quick-link').forEach(link => { link.addEventListener('click', () => { const section = link.dataset.section; renderSection(section, userId); const nl = document.querySelector(`.nav-link[data-section="${section}"]`); if (nl) { document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active')); nl.classList.add('active') } }); link.addEventListener('keydown', e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); link.click() } }) }) } function setupDailyChallenge(userId) { const completeBtn = document.getElementById('completeChallenge'); if (completeBtn) { completeBtn.addEventListener('click', () => { const result = StorageManager.completeDailyChallenge(userId); if (result) { showNotification('success', 'Daily challenge completed! +10 points'); AppState.updateDashboard(userId) } else { showNotification('info', 'You already completed today\'s challenge!') } }) } } function showNotification(type, message) { const notificationArea = document.getElementById('notificationArea'); if (!notificationArea) return; const notif = document.createElement('div'); notif.className = `notification ${type}`; notif.innerHTML = `<i class="fas fa-${type === 'success' ? 'check-circle' : type === 'error' ? 'exclamation-circle' : 'info-circle'}"></i><span>${message}</span>`; notificationArea.appendChild(notif); setTimeout(() => { notif.remove() }, 4e3) }